+std::vector<geometry_msgs::Point> interpolate_segment(
+  const geometry_msgs::Point & first,
+  const geometry_msgs::Point & second,
+  double sample_distance)
+{
+  if (sample_distance <= 0.) {
+    return {first, second};
+  }
+
+  double dx = second.x - first.x;
+  double dy = second.y - first.y;
+  double d = sqrt(dx * dx + dy * dy);
+  // Always generate both end points
+  uint32_t sample_count = std::max(2u, 1 + static_cast<uint32_t>(d / sample_distance));
+
+  std::vector<geometry_msgs::Point> samples(sample_count);
+
+  auto interpolate = [n = 0, N = sample_count, &first, &dx, &dy]() mutable {
+      double t = n++ / static_cast<double>(N - 1);
+      geometry_msgs::Point sample = first;
+      sample.x += t * dx;
+      sample.y += t * dy;
+      return sample;
+    };
+  std::generate(samples.begin(), samples.end(), interpolate);
+
+  return samples;
+}
+
+}  // namespace off_highway_uss

